using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using System;
using System.IO;
using System.Threading.Tasks;
using System.Collections.Generic;

[ApiController]
[Route("api/[controller]")]
public class UploadController : ControllerBase
{
    private readonly IWebHostEnvironment _hostEnvironment;

    public UploadController(IWebHostEnvironment hostEnvironment)
    {
        _hostEnvironment = hostEnvironment;
    }

    [HttpPost("Upload")]
    public async Task<IActionResult> Upload(List<IFormFile> files)
    {
        if (files == null || files.Count == 0)
        {
            return BadRequest("No files selected for upload.");
        }

        var uploadedFilePaths = new List<string>();
        var uploadsFolder = Path.Combine(_hostEnvironment.WebRootPath, "uploads");

        // Ensure the uploads directory exists
        if (!Directory.Exists(uploadsFolder))
        {
            Directory.CreateDirectory(uploadsFolder);
        }

        foreach (var file in files)
        {
            if (file.Length == 0)
            {
                continue; // Skip empty files
            }

            // Generate a unique file name to prevent overwriting issues
            var fileExtension = Path.GetExtension(file.FileName);
            var uniqueFileName = Guid.NewGuid().ToString() + fileExtension;
            var filePath = Path.Combine(uploadsFolder, uniqueFileName);

            try
            {
                // Save the file to the server's file system
                using (var stream = new FileStream(filePath, FileMode.Create))
                {
                    await file.CopyToAsync(stream);
                }

                // Add the relative path to the list to be returned
                uploadedFilePaths.Add($"/uploads/{uniqueFileName}");
            }
            catch (Exception ex)
            {
                // Log the exception if needed, and potentially return a partial success or error for this file
                Console.WriteLine($"Error uploading file {file.FileName}: {ex.Message}");
                // Optionally, you could add an error message to the response
                // For simplicity, we'll just skip this file and continue
            }
        }

        if (uploadedFilePaths.Count == 0)
        {
            return BadRequest("No files were successfully uploaded. Please check file sizes and types.");
        }

        // Return the list of relative paths for the successfully uploaded files
        return Ok(uploadedFilePaths);
    }
}